//! Integration tests for OKX DEX Router v1.0.7 using real Ethereum mainnet transactions.
//! Covers order-based swaps, beneficiary routing, Uniswap V3 routing, and UNX swaps.

use clear_signing::resolver::ResolvedDescriptor;
use clear_signing::token::{CompositeDataProvider, StaticTokenSource, TokenMeta, WellKnownTokenSource};
use clear_signing::types::descriptor::Descriptor;
use clear_signing::{format_calldata, DisplayEntry, DisplayModel, TransactionContext};

const OKX_ADDR: &str = "0x5E1f62Dac767b0491e3CE72469C217365D5B48cC";

fn load_descriptor() -> Descriptor {
    let path = format!(
        "{}/tests/fixtures/calldata-OkxDexRouterV1.0.7-multi-commission.json",
        env!("CARGO_MANIFEST_DIR")
    );
    let json = std::fs::read_to_string(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));
    Descriptor::from_json(&json).unwrap_or_else(|e| panic!("parse {path}: {e}"))
}

fn wrap_rd(descriptor: Descriptor) -> Vec<ResolvedDescriptor> {
    vec![ResolvedDescriptor {
        descriptor,
        chain_id: 1,
        address: OKX_ADDR.to_lowercase(),
    }]
}

fn decode_hex(hex_str: &str) -> Vec<u8> {
    let s = hex_str.strip_prefix("0x").unwrap_or(hex_str);
    hex::decode(s).unwrap_or_else(|e| panic!("invalid hex '{hex_str}': {e}"))
}

fn get_entry_value(model: &DisplayModel, label: &str) -> String {
    for entry in &model.entries {
        if let DisplayEntry::Item(item) = entry {
            if item.label == label {
                return item.value.clone();
            }
        }
    }
    panic!("no entry with label '{label}' found");
}

fn value_bytes(hex_str: &str) -> Option<Vec<u8>> {
    let s = hex_str.strip_prefix("0x").unwrap_or(hex_str);
    if s == "0" || s.is_empty() {
        return None;
    }
    let padded = format!("{:0>64}", s);
    Some(hex::decode(&padded).unwrap())
}

fn token_source() -> CompositeDataProvider {
    let mut custom = StaticTokenSource::new();
    let tokens: &[(&str, &str, u8, &str)] = &[
        (
            "0xa0b86991c6218b36c1d19d4a2e9eb0ce3606eb48",
            "USDC",
            6,
            "USD Coin",
        ),
        (
            "0xdac17f958d2ee523a2206206994597c13d831ec7",
            "USDT",
            6,
            "Tether USD",
        ),
        (
            "0xc02aaa39b223fe8d0a0e5c4f27ead9083c756cc2",
            "WETH",
            18,
            "Wrapped Ether",
        ),
        (
            "0xeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee",
            "ETH",
            18,
            "Ether",
        ),
        (
            "0x0000000000000000000000000000000000000000",
            "ETH",
            18,
            "Ether",
        ),
        (
            "0x85f6eb2bd5a062f5f8560be93fb7147e16c81472",
            "FLY",
            4,
            "Franklin",
        ),
        (
            "0x82a77710495a35549d2add797412b4a4497d33ef",
            "DOGZ",
            18,
            "Dogz",
        ),
        (
            "0x095a28639128641fd815edb35c15f3f6137333c9",
            "AYUMU",
            9,
            "Ayumu",
        ),
        (
            "0x7de1cb532a084956d32a2294175bf2a7a878ffb7",
            "HKDB",
            18,
            "HKDB",
        ),
        (
            "0x1f7566299f6111a0d492f473bdbe4a1ebd9cef56",
            "SAIYAN",
            18,
            "Super Saiyan",
        ),
    ];
    for (addr, symbol, decimals, name) in tokens {
        custom.insert(
            1,
            addr,
            TokenMeta {
                symbol: symbol.to_string(),
                decimals: *decimals,
                name: name.to_string(),
            },
        );
    }
    CompositeDataProvider::new(vec![
        Box::new(custom),
        Box::new(WellKnownTokenSource::new()),
    ])
}

async fn run_okx_test(calldata_hex: &str, from: &str) -> DisplayModel {
    let descriptor = load_descriptor();
    let descriptors = wrap_rd(descriptor);
    let calldata = decode_hex(calldata_hex);
    let provider = token_source();
    let tx = TransactionContext {
        chain_id: 1,
        to: OKX_ADDR,
        calldata: &calldata,
        value: None,
        from: Some(from),
        implementation_address: None,
    };
    format_calldata(&descriptors, &tx, &provider).await.unwrap()
}

#[tokio::test]
async fn okx_dag_swap_by_order_id() {
    // Real tx: 0x2c4a9bd8e4e0241ee561cbd296521805d57d8f8abcd512476ae65d4b2d863396
    let result = run_okx_test(
        "",
        "0xbb36acf8c156f19e9550d1f66b1cdd2cb003b65d",
    )
    .await;

    assert_eq!(result.intent, "Swap");
    assert_eq!(result.owner.as_deref(), Some("OKX Labs"));
    assert_eq!(get_entry_value(&result, "Order ID"), "17030407134781888");
    assert_eq!(get_entry_value(&result, "Amount to Send"), "5000000 FLY");
    assert_eq!(
        get_entry_value(&result, "Minimum to Receive"),
        "79.967291 USDT"
    );
    assert_eq!(
        get_entry_value(&result, "Deadline"),
        "2026-03-27 09:16:30 UTC"
    );
    assert!(result.warnings.is_empty());
}

