#[tokio::test]
async fn okx_unxswap_to() {
    // Real tx: 0x50af7de1f9cae41dd88f1fd05aecc2e376db0901e3fb0466dc40013f968d2973
    let result = run_okx_test(
        "",
        "0x66b72da284e5f7b810bf8c3b06b9dee6e2d57248",
    )
    .await;

    assert_eq!(result.intent, "Swap");
    assert_eq!(result.owner.as_deref(), Some("OKX Labs"));
    assert_eq!(
        get_entry_value(&result, "Beneficiary"),
        "0x66b72da284E5f7B810bF8c3B06b9DEe6E2d57248"
    );
    assert_eq!(get_entry_value(&result, "Amount to Send"), "0.5 USDT");
    // minReturn uses $ref to minReceiveAmount (tokenAmount) but has no tokenPath,
    // so it falls back to raw display
    assert_eq!(
        get_entry_value(&result, "Minimum to Receive"),
        "12398760893459956693590"
    );
}

